const shopid = $json.shopid;
const cookieStr = $json.cookie;

// 解析 Cookie
const cookies = cookieStr.split(';').map(c => {
  const eqIdx = c.indexOf('=');
  if (eqIdx === -1) return null;
  const name = c.substring(0, eqIdx).trim();
  const value = c.substring(eqIdx + 1).trim();
  return { name, value, domain: '.shopee.tw', path: '/' };
}).filter(c => c && c.name && c.value);

await $page.setCookie(...cookies);

// 拦截 search_items API 响应
let capturedData = null;
const responseHandler = async (response) => {
  const url = response.url();
  if (url.includes('/api/v4/search/search_items') && !capturedData) {
    try {
      const json = await response.json();
      if (json && (json.items || json.error !== undefined)) {
        capturedData = json;
      }
    } catch(e) {}
  }
};
$page.on('response', responseHandler);

// 导航到店铺页面
await $page.goto(`https://shopee.tw/shop/${shopid}/`, {
  waitUntil: 'domcontentloaded',
  timeout: 30000
});

// 等待页面渲染后滚动（触发懒加载 search_items 请求）
await new Promise(r => setTimeout(r, 2000));
await $page.evaluate(() => window.scrollBy(0, 600));
await new Promise(r => setTimeout(r, 1000));
await $page.evaluate(() => window.scrollBy(0, 600));
await new Promise(r => setTimeout(r, 1000));

// 等待捕获 API 响应（最多 12 秒）
let waited = 0;
while (!capturedData && waited < 12000) {
  await new Promise(r => setTimeout(r, 500));
  waited += 500;
}
$page.off('response', responseHandler);

if (!capturedData) {
  return [{ json: { error: 'not_captured', message: 'search_items not triggered after scroll' } }];
}

return [{ json: capturedData }];

