// 解析上新数据 —— 适配 Shopee 内部 API 返回格式
// Shopee API 返回结构：{ items: [{ item_basic: {...} }], ... }
// 价格单位为 1/100000 TWD（需除以 100000）

const input = $input.all();
const configItems = $('监控目标配置').all();
const results = [];

for (let idx = 0; idx < input.length; idx++) {
  const raw = input[idx].json;
  const shopName = configItems[idx]?.json?.shop_name || '未知店铺';
  const shopid = configItems[idx]?.json?.shopid || '';

  // Shopee API 标准返回：{ items: [...] }
  const items =
    raw?.items ||
    raw?.data?.items ||
    raw?.result?.items ||
    [];

  // 若请求失败（error code 非0）或无数据，输出调试信息
  if (items.length === 0) {
    results.push({
      json: {
        type: 'debug',
        shop_name: shopName,
        raw_response: raw,
        message: raw?.error
          ? `⚠️ Shopee API 返回错误码 ${raw.error}，Cookie 可能已失效，请重新导出`
          : '⚠️ 未获取到商品数据，请查看 raw_response'
      }
    });
    continue;
  }

  const newItems = items.slice(0, 5).map(i => {
    const info = i.item_basic || i;
    // Shopee 原始 API 价格单位为 1/100000 TWD
    const rawPrice = Number(info.price_min ?? info.price ?? 0);
    const price = rawPrice > 100000 ? (rawPrice / 100000).toFixed(0) : rawPrice.toFixed(0);
    const name = info.name || '未知商品';
    const itemid = info.itemid || info.id || '';
    const sid = info.shopid || shopid;
    const url = itemid && sid ? `https://shopee.tw/product/${sid}/${itemid}` : '';
    return { name, price, url };
  });

  if (newItems.length > 0) {
    results.push({
      json: {
        type: 'new_items',
        shop_name: shopName,
        items: newItems,
        check_time: new Date().toLocaleString('zh-TW', { timeZone: 'Asia/Taipei' })
      }
    });
  }
}

return results.length > 0 ? results : [{ json: { type: 'no_change', message: '本次检查无上新' } }];

// 解析价格数据，检测价格变动 —— 适配 Shopee 内部 API 返回格式

const input = $input.all();
const configItems = $('监控目标配置').all();
const results = [];

const staticData = $getWorkflowStaticData('global');
if (!staticData.priceHistory) staticData.priceHistory = {};

for (let idx = 0; idx < input.length; idx++) {
  const raw = input[idx].json;
  const shopName = configItems[idx]?.json?.shop_name || '未知店铺';
  const shopid = configItems[idx]?.json?.shopid || '';

  // Shopee API 标准返回：{ items: [...] }
  const items =
    raw?.items ||
    raw?.data?.items ||
    raw?.result?.items ||
    [];

  // 若请求失败，输出调试信息
  if (items.length === 0) {
    results.push({
      json: {
        type: 'debug',
        shop_name: shopName,
        raw_response: raw,
        message: raw?.error
          ? `⚠️ Shopee API 返回错误码 ${raw.error}，Cookie 可能已失效，请重新导出`
          : '⚠️ 未获取到商品数据，请查看 raw_response'
      }
    });
    continue;
  }

  const priceChanges = [];

  for (const i of items) {
    const info = i.item_basic || i;
    const itemid = String(info.itemid || info.id || '');
    const name = info.name || '未知商品';

    // Shopee 原始 API 价格单位为 1/100000 TWD
    const rawPrice = Number(info.price_min ?? info.price ?? 0);
    const currentPrice = rawPrice > 100000 ? (rawPrice / 100000).toFixed(0) : rawPrice.toFixed(0);

    if (!itemid || rawPrice === 0) continue;

    const key = `${shopName}_${itemid}`;
    const lastPrice = staticData.priceHistory[key];

    if (lastPrice && lastPrice !== currentPrice) {
      const diff = Number(currentPrice) - Number(lastPrice);
      const direction = diff > 0 ? '📈 涨价' : '📉 降价';
      const sid = info.shopid || shopid;
      const url = sid ? `https://shopee.tw/product/${sid}/${itemid}` : '';
      priceChanges.push({
        name,
        last_price: lastPrice,
        current_price: currentPrice,
        diff: Math.abs(diff),
        direction,
        url
      });
    }

    staticData.priceHistory[key] = currentPrice;
  }

  if (priceChanges.length > 0) {
    results.push({
      json: {
        type: 'price_change',
        shop_name: shopName,
        changes: priceChanges,
        check_time: new Date().toLocaleString('zh-TW', { timeZone: 'Asia/Taipei' })
      }
    });
  }
}

return results.length > 0 ? results : [{ json: { type: 'no_change', message: '本次检查价格无变动' } }];

// 组装飞书消息
const data = $json;
let text = '';

if (data.type === 'new_items') {
  text += `🆕 【上新提醒】${data.shop_name}\n`;
  text += `📅 检查时间：${data.check_time}\n\n`;
  for (const item of data.items) {
    text += `▪ ${item.name}\n`;
    text += `  💰 售价：NT$ ${item.price}\n`;
    if (item.url) text += `  🔗 ${item.url}\n`;
    text += '\n';
  }
} else if (data.type === 'price_change') {
  text += `💰 【价格变动】${data.shop_name}\n`;
  text += `📅 检查时间：${data.check_time}\n\n`;
  for (const c of data.changes) {
    text += `▪ ${c.name}\n`;
    text += `  ${c.direction}：NT$ ${c.last_price} → NT$ ${c.current_price}（变动 ${c.diff} 元）\n`;
    if (c.url) text += `  🔗 ${c.url}\n`;
    text += '\n';
  }
} else if (data.type === 'debug') {
  text += `⚠️ 【调试信息】${data.shop_name}\n`;
  text += `${data.message}\n`;
  text += `原始响应：${JSON.stringify(data.raw_response).slice(0, 500)}`;
}

return [{ json: { text: text.trim() } }];
